@overload
def _to_rust_reranker_config(value: None) -> None: ...


@overload
def _to_rust_reranker_config(value: RerankerConfig | dict[str, Any] | str) -> _rust.RerankerConfig: ...
def _to_rust_reranker_config(value: RerankerConfig | dict[str, Any] | str | None) -> _rust.RerankerConfig | None:
    """Convert Python RerankerConfig to Rust binding type."""
    if isinstance(value, str):
        value = json.loads(value)
    if isinstance(value, dict):
        if "acceleration" in value and value["acceleration"] is not None:
            value["acceleration"] = _to_rust_acceleration_config(value["acceleration"])
        if "model" in value and value["model"] is not None and not isinstance(value["model"], _rust.RerankerModelType):
            value["model"] = _rust.RerankerModelType(value["model"])
        value = RerankerConfig(**value)
    if value is None:
        return None
    value = cast(RerankerConfig, value)
    return _rust.RerankerConfig(
**({"model": value.model if isinstance(value.model, _rust.RerankerModelType) else _rust.RerankerModelType(value.model)} if value.model is not None else {}),
        top_k=value.top_k,
        batch_size=value.batch_size,
        show_download_progress=value.show_download_progress,
        cache_dir=value.cache_dir,
        acceleration=_to_rust_acceleration_config(value.acceleration),
        max_rerank_duration_secs=value.max_rerank_duration_secs,
    )


